// 奇偶构造常用思路
// 1. 分析奇偶性质对结果的影响
// 2. 根据奇偶性分类讨论
// 3. 利用奇偶性构造特殊排列

#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读取输入
    int n;
    cin >> n;

    // 根据奇偶性构造答案
    if (n % 2 == 0) {
        // 偶数情况的构造
        for (int i = 1; i <= n; i += 2) {
            cout << i + 1 << " " << i << " ";
        }
    } else {
        // 奇数情况的构造
        cout << "1 ";
        for (int i = 2; i <= n; i += 2) {
            cout << i + 1 << " " << i << " ";
        }
    }

    return 0;
}

// 顺序构造常用思路
// 1. 确定元素的排列顺序
// 2. 按照特定规则放置元素
// 3. 保证相邻元素满足条件

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    vector<int> arr(n);
    // 构造特定顺序的排列
    int l = 1, r = n;
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) {
            arr[i] = l++;
        } else {
            arr[i] = r--;
        }
    }

    // 输出结果
    for (int x : arr) {
        cout << x << " ";
    }

    return 0;
}

