// 逆向构造常用思路
// 1. 从最终状态向前推导
// 2. 还原操作序列
// 3. 确定可行的初始状态

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    // 从结果反推
    vector<int> target(n);
    for (int i = 0; i < n; i++) {
        cin >> target[i];
    }

    // 逆向推导初始状态
    vector<int> initial(n);
    for (int i = n - 1; i >= 0; i--) {
        // 根据目标状态和已知操作反推
        initial[i] = target[i] - 某些操作;
    }

    // 验证并输出
    if (验证成功) {
        for (int x : initial) {
            cout << x << " ";
        }
    } else {
        cout << "-1";
    }

    return 0;
}

// 网格构造常用思路
// 1. 设计矩阵的填充模式
// 2. 考虑行和列的性质
// 3. 处理边界和特殊情况

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<vector<int>> grid(n, vector<int>(m));

    // 构造网格
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            // 根据行列关系设计填充规则
            grid[i][j] = (i * 某种系数 + j) % 某个值 + 1;
        }
    }

    // 输出网格
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cout << grid[i][j] << " ";
        }
        cout << "\n";
    }

    return 0;
}

