// 图论构造常用思路
// 1. 设计图的连接方式
// 2. 保证图的特定性质（连通性、度数、路径等）
// 3. 使用DFS/BFS等算法辅助构造

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<pair<int, int>> edges;

    // 构造图结构
    if (需要满足特定性质) {
        // 设计连接策略
        for (int i = 1; i <= n; i++) {
            for (int j = i + 1; j <= n; j++) {
                if (满足连接条件) {
                    edges.push_back({i, j});
                    if (edges.size() == m) break;
                }
            }
            if (edges.size() == m) break;
        }
    }

    // 输出结果
    if (edges.size() == m) {
        for (auto [u, v] : edges) {
            cout << u << " " << v << "\n";
        }
    } else {
        cout << "-1";
    }

    return 0;
}

